// Cars - Simple car listing page without filters
import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import carService from '../services/bookingService';
import { formatCurrency } from '../utils/helpers';
import './Home.css';

const Cars = () => {
  const [cars, setCars] = useState([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    fetchCars();
  }, []);

  const fetchCars = async () => {
    try {
      setIsLoading(true);
      const response = await carService.getAllCars({ limit: 1000 });
      
      if (response.data) {
        setCars(response.data);
      }
    } catch (error) {
      console.error('Fetch cars error:', error);
      toast.error('Failed to load cars');
    } finally {
      setIsLoading(false);
    }
  };

  if (isLoading) {
    return (
      <div className="container" style={{ padding: '2rem', textAlign: 'center' }}>
        <div className="loading"></div>
        <p>Loading cars...</p>
      </div>
    );
  }

  return (
    <div className="container" style={{ padding: '2rem', maxWidth: '1400px', margin: '0 auto' }}>
      <div style={{ marginBottom: '2rem' }}>
        <h1 style={{ marginBottom: '0.5rem' }}>Available Cars</h1>
        <p style={{ color: '#6c757d' }}>Browse our collection of {cars.length} premium vehicles</p>
      </div>

      {cars.length === 0 ? (
        <div style={{
          background: '#f8f9fa',
          padding: '3rem',
          borderRadius: '0.5rem',
          textAlign: 'center',
        }}>
          <h3 style={{ color: '#6c757d' }}>No cars available</h3>
          <p style={{ color: '#adb5bd' }}>Please check back later</p>
        </div>
      ) : (
        <div className="cars-grid" style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))',
          gap: '2rem',
        }}>
          {cars.map(car => (
            <div key={car._id} className="car-card" style={{
              background: 'white',
              borderRadius: '0.5rem',
              overflow: 'hidden',
              boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
              transition: 'transform 0.3s ease, box-shadow 0.3s ease',
            }}>
              <div style={{ position: 'relative' }}>
                <img
                  src={car.images[0]?.startsWith('http') 
                    ? car.images[0] 
                    : `http://localhost:5000${car.images[0]}`}
                  alt={car.name}
                  style={{
                    width: '100%',
                    height: '200px',
                    objectFit: 'cover',
                  }}
                />
                {car.availabilityStatus && (
                  <div style={{
                    position: 'absolute',
                    top: '1rem',
                    right: '1rem',
                    background: '#28a745',
                    color: 'white',
                    padding: '0.25rem 0.75rem',
                    borderRadius: '1rem',
                    fontSize: '0.85rem',
                    fontWeight: 'bold',
                  }}>
                    Available
                  </div>
                )}
              </div>
              
              <div style={{ padding: '1.5rem' }}>
                <h3 style={{ margin: '0 0 0.5rem 0', fontSize: '1.25rem' }}>{car.name}</h3>
                <p style={{ margin: '0 0 1rem 0', color: '#6c757d', fontSize: '0.9rem' }}>
                  {car.brand} {car.model} • {car.year}
                </p>

                <div style={{
                  display: 'grid',
                  gridTemplateColumns: '1fr 1fr',
                  gap: '0.75rem',
                  marginBottom: '1rem',
                  fontSize: '0.85rem',
                }}>
                  <div>
                    <span style={{ color: '#6c757d' }}>🪑 </span>
                    <span>{car.seatingCapacity} Seats</span>
                  </div>
                  <div>
                    <span style={{ color: '#6c757d' }}>⛽ </span>
                    <span>{car.fuelType}</span>
                  </div>
                  <div>
                    <span style={{ color: '#6c757d' }}>⚙️ </span>
                    <span>{car.transmission}</span>
                  </div>
                  <div>
                    <span style={{ color: '#6c757d' }}>📊 </span>
                    <span>{car.mileage} km/l</span>
                  </div>
                </div>

                <div style={{
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                  marginBottom: '1rem',
                  paddingTop: '1rem',
                  borderTop: '1px solid #e0e0e0',
                }}>
                  <span style={{ color: '#6c757d', fontSize: '0.9rem' }}>Per Day</span>
                  <span style={{ fontSize: '1.5rem', fontWeight: 'bold', color: '#0066cc' }}>
                    {formatCurrency(car.rentPerDay)}
                  </span>
                </div>

                <Link
                  to={`/cars/${car._id}`}
                  className="btn btn-primary"
                  style={{
                    display: 'block',
                    textAlign: 'center',
                    textDecoration: 'none',
                    padding: '0.75rem',
                  }}
                >
                  View Details
                </Link>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default Cars;
